#@help _database_enumerate0
# @internal database enumeration helper for 'inspect'
#@end
_database_enumerate0() {
  # Terminal function - Database Structure Enumeration
  # Generation-time pattern: discover now, output only concrete comments

  echo "# Database Structure"
  echo "#"

  # Base directory
  if [ -d "$VPN_SWITCH_BASE" ]; then
    local base_perms=$(ls -ld "$VPN_SWITCH_BASE" 2>>"$LOG_FILE" | awk '{print $1}')
    echo "# $VPN_SWITCH_BASE ($base_perms)"
  else
    echo "# $VPN_SWITCH_BASE (NOT FOUND)"
  fi

  # Enumerate configured directories
  echo "$VPN_SWITCH_INIT_DIR_CONFIG" | while IFS=: read -r dir mode exec_flag; do
    [ -z "$dir" ] && continue
    local full_path="$VPN_SWITCH_BASE/$dir"
    if [ -d "$full_path" ]; then
      local perms=$(ls -ld "$full_path" 2>>"$LOG_FILE" | awk '{print $1}')
      local count=$(ls -1 "$full_path" 2>>"$LOG_FILE" | wc -l | tr -d ' ')
      echo "#   $dir/ ($perms, $count items)"
    elif [ -e "$full_path" ]; then
      echo "#   $dir (exists but not a directory)"
    else
      echo "#   $dir/ (missing)"
    fi
  done
}

