#@end
_prologue_inspect0() {
  # Define command variables from environment (hardcoded at generation time)
  echo "pfctl=\"\${VPN_SWITCH_PFCTL:-pfctl}\""
  echo "wg_quick=\"\$VPN_SWITCH_BINARY_wireguard\""
  echo "openvpn=\"\$VPN_SWITCH_BINARY_openvpn\""

  # Standard utilities
  echo "cat_cmd=\"\${VPN_SWITCH_CAT:-cat}\""
