#@help ___inspect0
# @command inspect
# @summary Full descriptive state dump (sessions, configs, phases, system)
# @group   diagnostics
# @returns diagnostic snapshot (always exits 0)
# @example vpn-switch inspect
# @see     validate
#@end
___inspect0() {
  # Save current settings (at generation time)
  ansi_original="${VPN_SWITCH_DISPLAY_ANSI}"
  cache_was_on=""
  if [ -n "${VPN_SWITCH_INTERPRETER_environment_cache}" ]; then
    cache_was_on="1"
  fi

  # Disable ANSI if currently enabled
  if [ "${VPN_SWITCH_DISPLAY_ANSI}" != "0" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" setenv VPN_SWITCH_DISPLAY_ANSI 0"
  fi

  # Enable cache for inspect (performance optimization)
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" environment cache on"

  # Delegate to all inspection functions (prologue FIRST!)
  # Note: Nested batch combinators (environment/wireguard/openvpn inspect) handle their own interpreter overrides
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" prologue inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" environment inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" system inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" status"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" wireguard inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" openvpn inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" session inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" phases inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" logs inspect"
  echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" summary inspect"

  # Restore ANSI to original value if we changed it
  if [ "${ansi_original}" != "0" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" setenv VPN_SWITCH_DISPLAY_ANSI ${ansi_original}"
  fi

  # Re-enable cache if it was enabled before
  if [ -n "$cache_was_on" ]; then
    echo "\"\$VPN_SWITCH_CONTEXT_SCRIPT\" environment cache on"
  fi
}

